import React from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  // THE LUXURY TERRACOTTA COLOR
  const terracotta = '#C04000'; 

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. THE NAVBAR (COMPACT & PROFESSIONAL) */}
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        padding: '15px 60px', 
        backgroundColor: '#050505', 
        position: 'sticky',
        top: 0,
        zIndex: 1000,
        borderBottom: `2px solid ${terracotta}` // Terracotta accent line
      }}>
        {/* LOGO ON THE LEFT */}
        <div style={{ display: 'flex', alignItems: 'center' }}>
          <img src={Logo} alt="Àmí by T" style={{ height: '45px', filter: 'contrast(110%) brightness(110%)' }} />
        </div>

        {/* NAVIGATION LINKS */}
        <div style={{ display: 'flex', gap: '35px' }}>
          {['Home', 'Small Chops', 'Office Lunch', 'About Us'].map((item) => (
            <a key={item} href={`#${item.toLowerCase().replace(' ', '')}`} style={{ 
              color: '#fff', 
              textDecoration: 'none', 
              fontSize: '0.85rem', 
              letterSpacing: '1px',
              textTransform: 'uppercase',
              fontWeight: '500',
              opacity: 0.8
            }}>
              {item}
            </a>
          ))}
        </div>

        {/* THE "0 ITEMS" BUTTON - IN TERRACOTTA */}
        <div style={{ 
          backgroundColor: terracotta, 
          color: '#fff', 
          padding: '8px 20px', 
          borderRadius: '4px', 
          fontSize: '0.75rem', 
          fontWeight: 'bold',
          letterSpacing: '1px',
          cursor: 'pointer',
          boxShadow: '0 4px 15px rgba(192, 64, 0, 0.2)'
        }}>
          0 ITEMS
        </div>
      </nav>

      {/* 2. THE MAIN CONTENT AREA */}
      <main style={{ padding: '20px 0' }}>
        
        {/* REFINED HEADER SECTION */}
        <div style={{ textAlign: 'center', padding: '70px 20px 40px' }}>
           <h1 style={{ 
             color: '#fff', 
             fontSize: '2.8rem', 
             marginBottom: '10px', 
             fontWeight: '300', 
             letterSpacing: '3px' 
           }}>
             Featured <span style={{ color: terracotta }}>Collections</span>
           </h1>
           {/* Terracotta underline */}
           <div style={{ width: '40px', height: '2px', backgroundColor: terracotta, margin: '0 auto 15px' }}></div>
           <p style={{ color: '#888', fontSize: '0.9rem', fontStyle: 'italic', letterSpacing: '1px' }}>
             Taste and Style curated for you
           </p>
        </div>

        {/* This displays your Small Chops (Starter, Signature, Owambe) */}
        <Menu />
        
        {/* Subtle Section Divider */}
        <div style={{ padding: '60px 0' }}>
            <hr style={{ border: '0', height: '1px', backgroundColor: '#1a1a1a', width: '80%', margin: '0 auto' }} />
        </div>
        
        {/* This displays your Office Lunch Subscriptions */}
        <div id="officelunch">
            <Lunch />
        </div>
      </main>

      {/* 3. FOOTER SECTION */}
      <footer style={{ 
        textAlign: 'center', 
        padding: '80px 40px', 
        backgroundColor: '#050505', 
        color: '#333', 
        fontSize: '0.7rem',
        borderTop: `1px solid ${terracotta}22` // Very faint terracotta top border
      }}>
        <p style={{ letterSpacing: '4px', color: '#555', marginBottom: '10px' }}>ÀMÍ BY T | LAGOS</p>
        <p>© 2026 ALL RIGHTS RESERVED</p>
      </footer>

    </div>
  );
}

export default App;
